import{_ as a,o as e,c as s,ag as n}from"./chunks/framework.CAXxHpAX.js";const h=JSON.parse('{"title":"GPU 指标","description":"Node Push Exporter GPU 指标详解","frontmatter":{"title":"GPU 指标","description":"Node Push Exporter GPU 指标详解"},"headers":[],"relativePath":"metrics/gpu.md","filePath":"metrics/gpu.md"}'),p={name:"metrics/gpu.md"};function d(l,t,o,i,c,r){return e(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="gpu-指标" tabindex="-1">GPU 指标 <a class="header-anchor" href="#gpu-指标" aria-label="Permalink to &quot;GPU 指标&quot;">​</a></h1><p>Node Push Exporter 通过 <code>nvidia-smi</code> 和 <code>rocm-smi</code> 采集 GPU 指标。</p><h2 id="📊-采集状态" tabindex="-1">📊 采集状态 <a class="header-anchor" href="#📊-采集状态" aria-label="Permalink to &quot;📊 采集状态&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th style="text-align:center;">类型</th><th>说明</th></tr></thead><tbody><tr><td><code>node_push_exporter_gpu_scrape_success</code></td><td style="text-align:center;">Gauge</td><td>采集是否成功 (1=成功, 0=失败)</td></tr><tr><td><code>node_push_exporter_gpu_devices_detected</code></td><td style="text-align:center;">Gauge</td><td>检测到的 GPU 数量</td></tr></tbody></table><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 检查 GPU 是否正确识别</span></span>
<span class="line"><span>node_push_exporter_gpu_devices_detected{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 按厂商统计 GPU 数量</span></span>
<span class="line"><span>sum by (vendor) (node_push_exporter_gpu_devices_detected{job=&quot;node&quot;})</span></span></code></pre></div><hr><h2 id="🌡️-温度指标" tabindex="-1">🌡️ 温度指标 <a class="header-anchor" href="#🌡️-温度指标" aria-label="Permalink to &quot;🌡️ 温度指标&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th style="text-align:center;">类型</th><th>说明</th></tr></thead><tbody><tr><td><code>gpu_temperature_celsius</code></td><td style="text-align:center;">Gauge</td><td>GPU 温度 (通用)</td></tr><tr><td><code>gpu_temperature_edge_celsius</code></td><td style="text-align:center;">Gauge</td><td>Edge 温度传感器</td></tr><tr><td><code>gpu_temperature_junction_celsius</code></td><td style="text-align:center;">Gauge</td><td>结温 (Junction)</td></tr><tr><td><code>gpu_temperature_mem_celsius</code></td><td style="text-align:center;">Gauge</td><td>显存温度</td></tr><tr><td><code>gpu_temperature_core_celsius</code></td><td style="text-align:center;">Gauge</td><td>核心温度 (备选)</td></tr></tbody></table><h3 id="温度告警阈值" tabindex="-1">温度告警阈值 <a class="header-anchor" href="#温度告警阈值" aria-label="Permalink to &quot;温度告警阈值&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">状态</th><th style="text-align:center;">温度</th><th>建议</th></tr></thead><tbody><tr><td style="text-align:center;">✅ 正常</td><td style="text-align:center;">&lt; 70°C</td><td>无需处理</td></tr><tr><td style="text-align:center;">⚠️ 警告</td><td style="text-align:center;">70-85°C</td><td>监控频率增加</td></tr><tr><td style="text-align:center;">🔥 危险</td><td style="text-align:center;">85-95°C</td><td>检查散热</td></tr><tr><td style="text-align:center;">💀 临界</td><td style="text-align:center;">&gt; 95°C</td><td>可能触发降频保护</td></tr></tbody></table><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 获取所有 GPU 温度</span></span>
<span class="line"><span>gpu_temperature_celsius{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 平均温度</span></span>
<span class="line"><span>avg by (instance) (gpu_temperature_celsius{job=&quot;node&quot;})</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 温度超过 80°C 的 GPU</span></span>
<span class="line"><span>gpu_temperature_celsius{job=&quot;node&quot;} &gt; 80</span></span></code></pre></div><hr><h2 id="📈-gpu-利用率" tabindex="-1">📈 GPU 利用率 <a class="header-anchor" href="#📈-gpu-利用率" aria-label="Permalink to &quot;📈 GPU 利用率&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th style="text-align:center;">类型</th><th>说明</th></tr></thead><tbody><tr><td><code>gpu_utilization_percent</code></td><td style="text-align:center;">Gauge</td><td>GPU 计算利用率 (%)</td></tr></tbody></table><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># GPU 利用率</span></span>
<span class="line"><span>gpu_utilization_percent{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 利用率超过 90%</span></span>
<span class="line"><span>gpu_utilization_percent{job=&quot;node&quot;} &gt; 90</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 平均利用率</span></span>
<span class="line"><span>avg by (instance) (gpu_utilization_percent{job=&quot;node&quot;})</span></span></code></pre></div><hr><h2 id="🎮-显存指标" tabindex="-1">🎮 显存指标 <a class="header-anchor" href="#🎮-显存指标" aria-label="Permalink to &quot;🎮 显存指标&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th style="text-align:center;">类型</th><th>说明</th></tr></thead><tbody><tr><td><code>gpu_memory_used_percent</code></td><td style="text-align:center;">Gauge</td><td>显存使用率 (%)</td></tr><tr><td><code>gpu_memory_used_bytes</code></td><td style="text-align:center;">Gauge</td><td>已使用显存 (bytes)</td></tr><tr><td><code>gpu_memory_total_bytes</code></td><td style="text-align:center;">Gauge</td><td>显存总量 (bytes)</td></tr></tbody></table><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 显存使用率</span></span>
<span class="line"><span>gpu_memory_used_percent{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 已用显存 (GB)</span></span>
<span class="line"><span>gpu_memory_used_bytes{job=&quot;node&quot;} / 1024^3</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 总显存 (GB)</span></span>
<span class="line"><span>gpu_memory_total_bytes{job=&quot;node&quot;} / 1024^3</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 使用率超过 80%</span></span>
<span class="line"><span>gpu_memory_used_percent{job=&quot;node&quot;} &gt; 80</span></span></code></pre></div><h2 id="🌀-其他指标" tabindex="-1">🌀 其他指标 <a class="header-anchor" href="#🌀-其他指标" aria-label="Permalink to &quot;🌀 其他指标&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th style="text-align:center;">类型</th><th>说明</th></tr></thead><tbody><tr><td><code>gpu_fan_speed_percent</code></td><td style="text-align:center;">Gauge</td><td>风扇转速 (%)</td></tr><tr><td><code>gpu_clock_sm_hertz</code></td><td style="text-align:center;">Gauge</td><td>GPU SM 频率 (Hz)</td></tr><tr><td><code>gpu_clock_mem_hertz</code></td><td style="text-align:center;">Gauge</td><td>显存频率 (Hz)</td></tr></tbody></table><hr><h2 id="🏷️-标签说明" tabindex="-1">🏷️ 标签说明 <a class="header-anchor" href="#🏷️-标签说明" aria-label="Permalink to &quot;🏷️ 标签说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>标签</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><code>vendor</code></td><td>GPU 厂商</td><td><code>nvidia</code>, <code>rocm</code></td></tr><tr><td><code>gpu</code></td><td>GPU 编号</td><td><code>0</code>, <code>1</code></td></tr><tr><td><code>name</code></td><td>GPU 型号</td><td><code>NVIDIA GeForce RTX 3090</code></td></tr><tr><td><code>uuid</code></td><td>GPU 唯一标识</td><td><code>GPU-xxxx-xxxx-xxxx-xxxx</code></td></tr><tr><td><code>device_id</code></td><td>设备 ID (AMD)</td><td><code>card0</code></td></tr></tbody></table><hr><h2 id="🔍-查询示例" tabindex="-1">🔍 查询示例 <a class="header-anchor" href="#🔍-查询示例" aria-label="Permalink to &quot;🔍 查询示例&quot;">​</a></h2><h3 id="gpu-状态总览" tabindex="-1">GPU 状态总览 <a class="header-anchor" href="#gpu-状态总览" aria-label="Permalink to &quot;GPU 状态总览&quot;">​</a></h3><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 所有 GPU 基本信息</span></span>
<span class="line"><span>gpu_info{job=&quot;node&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 温度 + 利用率 + 显存</span></span>
<span class="line"><span>gpu_temperature_celsius{job=&quot;node&quot;}</span></span>
<span class="line"><span>gpu_utilization_percent{job=&quot;node&quot;}</span></span>
<span class="line"><span>gpu_memory_used_percent{job=&quot;node&quot;}</span></span>
<span class="line"><span>gpu_power_draw_watts{job=&quot;node&quot;}</span></span></code></pre></div><h3 id="按实例汇总" tabindex="-1">按实例汇总 <a class="header-anchor" href="#按实例汇总" aria-label="Permalink to &quot;按实例汇总&quot;">​</a></h3><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># GPU 数量</span></span>
<span class="line"><span>sum by (instance) (node_push_exporter_gpu_devices_detected{job=&quot;node&quot;})</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 平均温度 / 利用率 / 功耗</span></span>
<span class="line"><span>avg by (instance) (gpu_temperature_celsius{job=&quot;node&quot;})</span></span>
<span class="line"><span>avg by (instance) (gpu_utilization_percent{job=&quot;node&quot;})</span></span>
<span class="line"><span>sum by (instance) (gpu_power_draw_watts{job=&quot;node&quot;})</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 总显存使用 (GB)</span></span>
<span class="line"><span>sum by (instance) (gpu_memory_used_bytes{job=&quot;node&quot;}) / 1024^3</span></span></code></pre></div><h3 id="按厂商分析" tabindex="-1">按厂商分析 <a class="header-anchor" href="#按厂商分析" aria-label="Permalink to &quot;按厂商分析&quot;">​</a></h3><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 各厂商 GPU 数量</span></span>
<span class="line"><span>count by (vendor) (gpu_info{job=&quot;node&quot;})</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 各厂商平均利用率</span></span>
<span class="line"><span>avg by (vendor) (gpu_utilization_percent{job=&quot;node&quot;})</span></span></code></pre></div><hr><h2 id="🔧-故障排查" tabindex="-1">🔧 故障排查 <a class="header-anchor" href="#🔧-故障排查" aria-label="Permalink to &quot;🔧 故障排查&quot;">​</a></h2><h3 id="gpu-采集失败" tabindex="-1">GPU 采集失败 <a class="header-anchor" href="#gpu-采集失败" aria-label="Permalink to &quot;GPU 采集失败&quot;">​</a></h3><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 找出采集失败的实例</span></span>
<span class="line"><span>node_push_exporter_gpu_scrape_success{job=&quot;node&quot;} == 0</span></span></code></pre></div><p>可能原因：</p><ul><li>❌ 未安装 GPU 驱动</li><li>❌ <code>nvidia-smi</code> 或 <code>rocm-smi</code> 不在 PATH</li><li>❌ 无 GPU 设备</li><li>❌ 权限不足</li></ul><h3 id="检测到-0-个-gpu" tabindex="-1">检测到 0 个 GPU <a class="header-anchor" href="#检测到-0-个-gpu" aria-label="Permalink to &quot;检测到 0 个 GPU&quot;">​</a></h3><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 检查设备数量</span></span>
<span class="line"><span>node_push_exporter_gpu_devices_detected{job=&quot;node&quot;} == 0</span></span></code></pre></div><p>可能原因：</p><ul><li>系统没有 GPU</li><li>GPU 驱动未加载</li><li>虚拟化环境未穿透 GPU</li></ul><h3 id="手动验证" tabindex="-1">手动验证 <a class="header-anchor" href="#手动验证" aria-label="Permalink to &quot;手动验证&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># NVIDIA</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nvidia-smi</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># AMD ROCm</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rocm-smi</span></span></code></pre></div>`,44)])])}const g=a(p,[["render",d]]);export{h as __pageData,g as default};
